mapper.update:
UPDATE exam_paper SET answer_status = #{answerStatus},
    submit_time = #{submitTime}, auto_submit = #{autoSubmit}, used_minutes = #{usedMinutes},
    objective_score = #{objectiveScore}, subjective_score = #{subjectiveScore},
    total_score = #{totalScore}, cut_screen_count = #{cutScreenCount},
    violation_count = #{violationCount}
WHERE id = #{id}

mapper.select:
SELECT ep.id AS examPaperId, ep.exam_id AS examId, ep.student_id AS studentId, ep.answer_status AS answerStatus, ep.total_score AS totalScore, ep.used_minutes AS usedMinutes, ep.submit_time AS submitTime, ep.create_time AS createTime, e.exam_name AS examName, u.real_name AS studentName, u.student_no AS studentNo FROM exam_paper ep JOIN exam e ON ep.exam_id = e.id JOIN sys_user u ON ep.student_id = u.id
AND u.real_name LIKE CONCAT('%', #{studentName}, '%')
ORDER BY ep.create_time DESC LIMIT #{limit} OFFSET #{offset}
